import{_ as n,o as e,c as t,a2 as a}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Context Management: Tools & Projects Ecosystem","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/context-management/tools-and-projects.md","filePath":"research/concepts/context-management/tools-and-projects.md"}'),o={name:"research/concepts/context-management/tools-and-projects.md"};function l(r,s,p,i,c,d){return e(),t("div",null,[...s[0]||(s[0]=[a(`<h1 id="context-management-tools-projects-ecosystem" tabindex="-1">Context Management: Tools &amp; Projects Ecosystem <a class="header-anchor" href="#context-management-tools-projects-ecosystem" aria-label="Permalink to &quot;Context Management: Tools &amp; Projects Ecosystem&quot;">​</a></h1><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>The context management tools ecosystem spans five distinct layers, each addressing a different aspect of the fundamental challenge: making the most of finite context windows.</p><p><strong>The five layers:</strong></p><ol><li><strong>Tokenization &amp; Counting</strong> — Know exactly how much space you have</li><li><strong>Code Intelligence &amp; Parsing</strong> — Understand code structure, not just text</li><li><strong>Memory &amp; Long-Context Systems</strong> — Manage what stays in and what gets evicted</li><li><strong>Code RAG &amp; Retrieval</strong> — Find and inject the right context on demand</li><li><strong>Persistence &amp; Memory Stores</strong> — Remember across sessions and conversations</li></ol><p>These are the building blocks that coding agents compose into their context management strategies. No single tool solves the problem — agents combine tools across layers. Aider uses tiktoken + tree-sitter + SQLite. Cursor uses embeddings + tree-sitter + vector stores. OpenHands chains condensers with retrieval. Understanding these tools individually is essential to understanding how agents build their context pipelines.</p><hr><h2 id="_2-tokenization-counting-tools" tabindex="-1">2. Tokenization &amp; Counting Tools <a class="header-anchor" href="#_2-tokenization-counting-tools" aria-label="Permalink to &quot;2. Tokenization &amp; Counting Tools&quot;">​</a></h2><p>Accurate token counting is the foundation. Every context management decision — what to include, what to evict, when to summarize — depends on knowing how many tokens something costs. Off-by-20% errors compound into either wasted capacity or context overflow crashes.</p><h3 id="tiktoken" tabindex="-1">tiktoken <a class="header-anchor" href="#tiktoken" aria-label="Permalink to &quot;tiktoken&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/openai/tiktoken" target="_blank" rel="noreferrer">https://github.com/openai/tiktoken</a></li><li><strong>License:</strong> MIT</li><li><strong>Language:</strong> Python with Rust core (via PyO3)</li><li><strong>Stars:</strong> 12k+ (as of 2025)</li></ul><p>OpenAI&#39;s fast BPE tokenizer. The reference implementation for counting tokens against OpenAI models. It is 3–6x faster than alternatives like <code>transformers</code> tokenizers for the same encodings.</p><p><strong>Encodings:</strong></p><table tabindex="0"><thead><tr><th>Encoding</th><th>Models</th><th>Vocab Size</th></tr></thead><tbody><tr><td><code>cl100k_base</code></td><td>GPT-4, GPT-3.5-turbo, text-embedding-ada-002</td><td>100,256</td></tr><tr><td><code>o200k_base</code></td><td>GPT-4o, o1, o3, o4-mini</td><td>200,019</td></tr><tr><td><code>p50k_base</code></td><td>text-davinci-002/003, Codex</td><td>50,281</td></tr></tbody></table><p><strong>How agents use it:</strong></p><ul><li>Aider uses tiktoken for exact token counting of repo-maps and chat messages</li><li>Many agents use it for budget management: &quot;do I have room for this file?&quot;</li><li>Cost estimation before API calls</li></ul><p><strong>Key pattern:</strong> exact counting for short text, sampling for long text.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> tiktoken</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Get encoding for a specific model</span></span>
<span class="line"><span style="color:#CDD6F4;">enc </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tiktoken</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">encoding_for_model</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;gpt-4o&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Or by encoding name directly</span></span>
<span class="line"><span style="color:#CDD6F4;">enc </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tiktoken</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">get_encoding</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;cl100k_base&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">tokens </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> enc</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">encode</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello, world!&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;font-style:italic;">len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tokens</span><span style="color:#9399B2;">))</span><span style="color:#6C7086;font-style:italic;">  # 4</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tokens</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">        # [9906, 11, 1917, 0]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Decode back</span></span>
<span class="line"><span style="color:#CDD6F4;">text </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> enc</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">decode</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tokens</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">          # &quot;Hello, world!&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Count tokens for a code file</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> count_file_tokens</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">path</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> encoding</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#94E2D5;"> =</span><span style="color:#A6E3A1;"> &quot;cl100k_base&quot;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    enc </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tiktoken</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">get_encoding</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">encoding</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    with</span><span style="color:#FAB387;font-style:italic;"> open</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">path</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> f</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">enc</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">encode</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">f</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">read</span><span style="color:#9399B2;">()))</span></span></code></pre></div><p><strong>Performance note:</strong> tiktoken uses Rust under the hood, making it fast enough to count tokens on every keystroke in editor integrations. For very large files (100K+ lines), agents sample a subset and extrapolate.</p><h3 id="hugging-face-tokenizers" tabindex="-1">Hugging Face tokenizers <a class="header-anchor" href="#hugging-face-tokenizers" aria-label="Permalink to &quot;Hugging Face tokenizers&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/huggingface/tokenizers" target="_blank" rel="noreferrer">https://github.com/huggingface/tokenizers</a></li><li><strong>License:</strong> Apache 2.0</li><li><strong>Language:</strong> Rust core, bindings for Python, Node.js, Ruby</li></ul><p>The universal tokenizer library. Supports every major tokenization algorithm: BPE, WordPiece, Unigram, and SentencePiece. Works with any model on Hugging Face Hub, not just OpenAI models.</p><p><strong>Key differentiator:</strong> alignment tracking — map tokens back to exact source spans. This is critical for code agents that need to know which bytes correspond to which tokens (e.g., for highlighting, error localization, or partial context extraction).</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> tokenizers </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> Tokenizer</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Load any model&#39;s tokenizer from HuggingFace Hub</span></span>
<span class="line"><span style="color:#CDD6F4;">tokenizer </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> Tokenizer</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">from_pretrained</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;gpt2&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">output </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tokenizer</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">encode</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;def hello():&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">tokens</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">    # [&#39;def&#39;, &#39;Ġhello&#39;, &#39;():&#39;]</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">ids</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">       # [4299, 23748, 33529]</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">offsets</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">   # [(0, 3), (3, 9), (9, 12)]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Alignment: token 1 (&#39;Ġhello&#39;) maps to source bytes 3-9</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># This enables precise code-span-to-token mapping</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Batch encoding for efficiency</span></span>
<span class="line"><span style="color:#CDD6F4;">outputs </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tokenizer</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">encode_batch</span><span style="color:#9399B2;">([</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;def foo(): pass&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;class Bar: ...&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;import os&quot;</span></span>
<span class="line"><span style="color:#9399B2;">])</span></span>
<span class="line"><span style="color:#CDD6F4;">total_tokens </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;font-style:italic;"> sum</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;font-style:italic;">len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">o</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">ids</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> for</span><span style="color:#CDD6F4;"> o </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> outputs</span><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>How agents use it:</strong></p><ul><li>Universal tokenizer when supporting multiple model providers (OpenAI, Anthropic, local)</li><li>Alignment tracking for precise code mapping (which function costs how many tokens)</li><li>Batch encoding when processing entire repositories</li></ul><h3 id="gpt-tokenizer" tabindex="-1">gpt-tokenizer <a class="header-anchor" href="#gpt-tokenizer" aria-label="Permalink to &quot;gpt-tokenizer&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/niieani/gpt-tokenizer" target="_blank" rel="noreferrer">https://github.com/niieani/gpt-tokenizer</a></li><li><strong>License:</strong> MIT</li><li><strong>Language:</strong> TypeScript, browser-ready (no WASM/native dependencies)</li></ul><p>The go-to tokenizer for JavaScript/TypeScript environments. Runs in browsers, Node.js, Deno, and edge runtimes. Critical for web-based coding tools.</p><p><strong>Key features:</strong></p><ul><li><code>isWithinTokenLimit(text, limit)</code> — early-exit check without full encoding</li><li><code>estimateCost(text, model)</code> — direct cost estimation</li><li>Streaming encode/decode via async iterators</li></ul><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> encode</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> isWithinTokenLimit </span><span style="color:#9399B2;">}</span><span style="color:#CBA6F7;"> from</span><span style="color:#A6E3A1;"> &#39;gpt-tokenizer&#39;</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Quick count</span></span>
<span class="line"><span style="color:#CBA6F7;">const</span><span style="color:#CDD6F4;"> tokens </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> encode</span><span style="color:#CDD6F4;">(</span><span style="color:#A6E3A1;">&quot;Hello, world!&quot;</span><span style="color:#CDD6F4;">)</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CDD6F4;">console</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">log</span><span style="color:#CDD6F4;">(tokens</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">length)</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;"> // 4</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Early-exit: returns false immediately if limit exceeded</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Does NOT encode the entire string — stops as soon as limit is hit</span></span>
<span class="line"><span style="color:#CBA6F7;">const</span><span style="color:#CDD6F4;"> fits </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> isWithinTokenLimit</span><span style="color:#CDD6F4;">(</span><span style="color:#A6E3A1;">&quot;...very long text...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 4096</span><span style="color:#CDD6F4;">)</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#CDD6F4;"> (</span><span style="color:#94E2D5;">!</span><span style="color:#CDD6F4;">fits) </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">  console</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">log</span><span style="color:#CDD6F4;">(</span><span style="color:#A6E3A1;">&quot;Text exceeds context window&quot;</span><span style="color:#CDD6F4;">)</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Key pattern:</strong> client-side token counting in web UIs. Cursor, Continue, and similar tools use this pattern to show token counts in real-time without round-tripping to a server.</p><h3 id="llama-tokenizer-js" tabindex="-1">llama-tokenizer-js <a class="header-anchor" href="#llama-tokenizer-js" aria-label="Permalink to &quot;llama-tokenizer-js&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/belladoreai/llama-tokenizer-js" target="_blank" rel="noreferrer">https://github.com/belladoreai/llama-tokenizer-js</a></li><li><strong>License:</strong> MIT</li><li><strong>Language:</strong> JavaScript, pure client-side</li></ul><p>Client-side tokenization for LLaMA/Llama family models. Runs in ~1ms for typical inputs.</p><p><strong>Critical insight:</strong> LLaMA and OpenAI token counts differ by ~20% for the same text. Code that is 1,000 tokens in cl100k_base might be 1,200 tokens in LLaMA&#39;s tokenizer. Agents supporting multiple providers must use the correct tokenizer or risk overflow/underutilization.</p><hr><h2 id="_3-code-intelligence-parsing-tools" tabindex="-1">3. Code Intelligence &amp; Parsing Tools <a class="header-anchor" href="#_3-code-intelligence-parsing-tools" aria-label="Permalink to &quot;3. Code Intelligence &amp; Parsing Tools&quot;">​</a></h2><p>Raw text tokenization tells you <em>how much</em> something costs. Code intelligence tells you <em>what</em> to include. These tools understand code structure — functions, classes, imports, call graphs — enabling agents to make informed decisions about which pieces of context matter most.</p><h3 id="tree-sitter" tabindex="-1">tree-sitter <a class="header-anchor" href="#tree-sitter" aria-label="Permalink to &quot;tree-sitter&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/tree-sitter/tree-sitter" target="_blank" rel="noreferrer">https://github.com/tree-sitter/tree-sitter</a></li><li><strong>License:</strong> MIT</li><li><strong>Language:</strong> C core, bindings for Python, Rust, JavaScript, Go, Java, Swift, and more</li><li><strong>Stars:</strong> 18k+ (as of 2025)</li></ul><p>The foundational parsing library for the coding agent ecosystem. Provides incremental, error-tolerant parsing for 100+ programming languages.</p><p><strong>Core properties:</strong></p><ul><li><strong>General:</strong> one API for any language via grammar plugins</li><li><strong>Fast:</strong> parses on every keystroke (sub-millisecond for incremental updates)</li><li><strong>Robust:</strong> produces useful ASTs even with syntax errors (critical for in-progress code)</li><li><strong>Dependency-free:</strong> no external toolchains required</li></ul><p><strong>Language support:</strong> C, C++, C#, Python, JavaScript, TypeScript, Java, Go, Rust, Ruby, PHP, Swift, Kotlin, Scala, Haskell, OCaml, Elixir, HTML, CSS, JSON, YAML, TOML, Markdown, Bash, SQL, and 80+ more.</p><p><strong>How agents use it:</strong></p><ol><li><p><strong>Aider:</strong> builds repo-map by extracting all definitions and references, then constructs a dependency graph ranked by PageRank. This map tells the LLM which files and symbols exist without including full source code.</p></li><li><p><strong>Cursor:</strong> code intelligence for navigation, symbol extraction, and understanding code structure for context assembly.</p></li><li><p><strong>GitHub Copilot:</strong> code understanding for suggestion generation, using tree-sitter to parse surrounding code and identify relevant context.</p></li></ol><p><strong>Key patterns:</strong></p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> tree_sitter_python </span><span style="color:#CBA6F7;">as</span><span style="color:#CDD6F4;"> tspython</span></span>
<span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> tree_sitter </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> Language</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> Parser</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Initialize parser</span></span>
<span class="line"><span style="color:#CDD6F4;">PY_LANGUAGE </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Language</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tspython</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">language</span><span style="color:#9399B2;">())</span></span>
<span class="line"><span style="color:#CDD6F4;">parser </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Parser</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">PY_LANGUAGE</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">source </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;font-style:italic;"> b</span><span style="color:#A6E3A1;">&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">class UserAuth:</span></span>
<span class="line"><span style="color:#A6E3A1;">    def login(self, username, password):</span></span>
<span class="line"><span style="color:#A6E3A1;">        token = self.generate_jwt(username)</span></span>
<span class="line"><span style="color:#A6E3A1;">        return token</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">    def logout(self, token):</span></span>
<span class="line"><span style="color:#A6E3A1;">        self.revoke(token)</span></span>
<span class="line"><span style="color:#A6E3A1;">&quot;&quot;&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">tree </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> parser</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">parse</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">source</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Extract all function definitions</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> extract_functions</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">node</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">type </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;function_definition&quot;</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        name_node </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> node</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">child_by_field_name</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;name&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">        yield</span><span style="color:#CDD6F4;"> name_node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">decode</span><span style="color:#9399B2;">(),</span><span style="color:#CDD6F4;"> node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">start_point</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">end_point</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> child </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">children</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        yield from</span><span style="color:#89B4FA;"> extract_functions</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">child</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> start</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> end </span><span style="color:#CBA6F7;">in</span><span style="color:#89B4FA;"> extract_functions</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tree</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">root_node</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    print</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;font-style:italic;">f</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">name</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">: lines </span><span style="color:#F5C2E7;">{</span><span style="color:#EBA0AC;font-style:italic;">start</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;font-style:italic;">0</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">+</span><span style="color:#FAB387;">1</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">-</span><span style="color:#F5C2E7;">{</span><span style="color:#EBA0AC;font-style:italic;">end</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;font-style:italic;">0</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">+</span><span style="color:#FAB387;">1</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># login: lines 3-5</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># logout: lines 7-8</span></span></code></pre></div><h3 id="ast-grep" tabindex="-1">ast-grep <a class="header-anchor" href="#ast-grep" aria-label="Permalink to &quot;ast-grep&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/ast-grep/ast-grep" target="_blank" rel="noreferrer">https://github.com/ast-grep/ast-grep</a></li><li><strong>License:</strong> MIT</li><li><strong>Language:</strong> Rust, CLI tool with WASM playground</li></ul><p>Structural code search and replace built on top of tree-sitter. Uses pattern syntax with <code>$MATCH</code> wildcards instead of regex, so searches are AST-aware rather than text-based.</p><p><strong>Why it matters for context management:</strong> agents can find structurally relevant code (all callers of a function, all implementations of an interface) rather than relying on text grep, which produces false positives.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Find all functions that call .save()</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &#39;$FUNC.save()&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> python</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Find all try/except blocks that catch generic Exception</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &#39;try: $$$ except Exception as $E: $$$&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> python</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Find React components with useState</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &#39;const [$STATE, $SETTER] = useState($INIT)&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> tsx</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Structural replace: rename a method across the codebase</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &#39;$OBJ.old_method($$$ARGS)&#39;</span><span style="color:#A6E3A1;"> -r</span><span style="color:#A6E3A1;"> &#39;$OBJ.new_method($$$ARGS)&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> python</span></span></code></pre></div><h3 id="aider-repo-map-grep-ast" tabindex="-1">Aider repo-map (grep-ast) <a class="header-anchor" href="#aider-repo-map-grep-ast" aria-label="Permalink to &quot;Aider repo-map (grep-ast)&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/Aider-AI/aider" target="_blank" rel="noreferrer">https://github.com/Aider-AI/aider</a></li><li><strong>License:</strong> Apache 2.0</li></ul><p>Aider&#39;s repo-map is the gold standard for structural code understanding in agents. It provides a concise, ranked overview of a repository that fits within a token budget.</p><p><strong>Three-step pipeline:</strong></p><ol><li><strong>tree-sitter parsing</strong> — extract all definitions (classes, functions, methods) and references (identifiers, calls) from every file</li><li><strong>Dependency graph construction</strong> — build a graph where nodes are files and edges represent cross-file references (file A references symbol defined in file B)</li><li><strong>PageRank scoring</strong> — rank files by importance using the same algorithm Google uses for web pages. Files referenced by many others rank higher.</li></ol><p><strong>Default budget:</strong> 1,024 tokens for the map, expandable up to 8,192 tokens for larger repos. The map is regenerated on each prompt, focused on files most relevant to the current conversation.</p><p><strong>Output format:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>src/auth/jwt.py</span></span>
<span class="line"><span>│ class JWTManager</span></span>
<span class="line"><span>│   def generate_token(self, user_id, claims)</span></span>
<span class="line"><span>│   def validate_token(self, token)</span></span>
<span class="line"><span>│   def refresh_token(self, token)</span></span>
<span class="line"><span>src/auth/middleware.py</span></span>
<span class="line"><span>│ class AuthMiddleware</span></span>
<span class="line"><span>│   def __call__(self, request)</span></span>
<span class="line"><span>│   def _extract_token(self, request)</span></span></code></pre></div><p>This gives the LLM a structural understanding of the codebase without consuming tokens on implementation details.</p><h3 id="sourcegraph-scip" tabindex="-1">Sourcegraph / SCIP <a class="header-anchor" href="#sourcegraph-scip" aria-label="Permalink to &quot;Sourcegraph / SCIP&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://sourcegraph.com" target="_blank" rel="noreferrer">https://sourcegraph.com</a></li><li><strong>SCIP URL:</strong> <a href="https://github.com/sourcegraph/scip" target="_blank" rel="noreferrer">https://github.com/sourcegraph/scip</a></li><li><strong>License:</strong> Apache 2.0 (SCIP), proprietary (Sourcegraph platform)</li></ul><p>Production-grade code intelligence at scale. Sourcegraph&#39;s architecture layers three levels of code understanding:</p><ol><li><strong>Precise indexers</strong> (SCIP) — compiler-level accuracy for Go, Java, TypeScript, Python</li><li><strong>tree-sitter</strong> — syntax-level intelligence for 30+ additional languages</li><li><strong>Text search</strong> — fallback for everything else (Zoekt trigram index)</li></ol><p><strong>How agents use it:</strong> Cody (Sourcegraph&#39;s AI assistant) uses this layered approach for cross-repository code navigation and context assembly. When you ask &quot;how does authentication work?&quot;, it can follow import chains across multiple repositories.</p><hr><h2 id="_4-memory-long-context-systems" tabindex="-1">4. Memory &amp; Long-Context Systems <a class="header-anchor" href="#_4-memory-long-context-systems" aria-label="Permalink to &quot;4. Memory &amp; Long-Context Systems&quot;">​</a></h2><p>These tools manage what stays in the context window and what gets evicted, summarized, or stored externally. They represent the &quot;working memory&quot; layer of coding agents.</p><h3 id="letta-memgpt" tabindex="-1">Letta / MemGPT <a class="header-anchor" href="#letta-memgpt" aria-label="Permalink to &quot;Letta / MemGPT&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/letta-ai/letta" target="_blank" rel="noreferrer">https://github.com/letta-ai/letta</a></li><li><strong>License:</strong> Apache 2.0</li><li><strong>Stars:</strong> 13k+ (as of 2025)</li></ul><p>The most radical approach to context management: treat the context window like RAM in an operating system, and let the agent manage its own memory via tool calls.</p><p><strong>Memory hierarchy:</strong></p><ul><li><strong>core_memory</strong> — always in-context, like CPU registers. Contains essential facts about the user and current task. Read/write via tools.</li><li><strong>archival_memory</strong> — vector-backed persistent storage, like a hard drive. Agent can insert and search. Unlimited capacity.</li><li><strong>conversation_search</strong> — recall buffer for past conversation turns. Agent can search by keyword or semantic similarity.</li></ul><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># These are tools the AGENT calls (not the developer)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># The agent decides when to save/retrieve information</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Agent stores a preference it learned</span></span>
<span class="line"><span style="color:#89B4FA;">core_memory_append</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    section</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;human&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    content</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;Prefers TypeScript over JavaScript for new projects&quot;</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Agent archives detailed technical context</span></span>
<span class="line"><span style="color:#89B4FA;">archival_memory_insert</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    content</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;The auth module uses JWT tokens stored in HttpOnly cookies. &quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;Refresh tokens are rotated on each use. See src/auth/jwt.ts.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Agent retrieves context when needed</span></span>
<span class="line"><span style="color:#CDD6F4;">results </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> archival_memory_search</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">query</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;authentication approach&quot;</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> count</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">5</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Agent manages its own context budget</span></span>
<span class="line"><span style="color:#89B4FA;">core_memory_replace</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    section</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;task&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    old_content</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;Working on: initial project setup&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    new_content</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;Working on: implementing OAuth2 flow&quot;</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Key insight:</strong> Letta inverts the typical pattern. Instead of the <em>system</em> deciding what to keep (sliding window, summarization), the <em>agent itself</em> makes memory management decisions. This allows for much more intelligent retention — the agent knows what&#39;s important.</p><h3 id="langchain-langgraph" tabindex="-1">LangChain / LangGraph <a class="header-anchor" href="#langchain-langgraph" aria-label="Permalink to &quot;LangChain / LangGraph&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/langchain-ai/langchain" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langchain</a></li><li><strong>License:</strong> MIT</li><li><strong>Stars:</strong> 100k+ (as of 2025)</li></ul><p>LangChain provides a menu of composable memory strategies. LangGraph adds checkpoint-based persistence for stateful agent workflows.</p><p><strong>Memory strategies (LangChain):</strong></p><table tabindex="0"><thead><tr><th>Strategy</th><th>Mechanism</th><th>Token Cost</th><th>Best For</th></tr></thead><tbody><tr><td><code>ConversationBufferMemory</code></td><td>Keep everything</td><td>O(n) growing</td><td>Short conversations</td></tr><tr><td><code>ConversationBufferWindowMemory</code></td><td>Sliding window (k turns)</td><td>O(k) fixed</td><td>Chat interfaces</td></tr><tr><td><code>ConversationSummaryMemory</code></td><td>LLM summarization</td><td>O(1) compressed</td><td>Long conversations</td></tr><tr><td><code>ConversationSummaryBufferMemory</code></td><td>Recent turns + summary</td><td>O(k + summary)</td><td>Balanced approach</td></tr><tr><td><code>ConversationTokenBufferMemory</code></td><td>Token-based window</td><td>O(budget) fixed</td><td>Budget-constrained</td></tr><tr><td><code>ConversationEntityMemory</code></td><td>Entity tracking</td><td>O(entities)</td><td>Character/concept tracking</td></tr><tr><td><code>VectorStoreRetrieverMemory</code></td><td>RAG-based recall</td><td>O(k retrieved)</td><td>Large knowledge bases</td></tr></tbody></table><p><strong>LangGraph persistence:</strong></p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> langgraph</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">checkpoint</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">sqlite </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> SqliteSaver</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Checkpoint-based persistence: every agent state is saved</span></span>
<span class="line"><span style="color:#CDD6F4;">checkpointer </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> SqliteSaver</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">from_conn_string</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;agent_state.db&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Agent can resume from any checkpoint</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Enables: undo/redo, branching conversations, crash recovery</span></span></code></pre></div><p><strong>Key pattern:</strong> composable memory — chain multiple strategies. Use token buffer for recent context + summary for older context + vector retrieval for long-term facts.</p><h3 id="openhands-condensers" tabindex="-1">OpenHands Condensers <a class="header-anchor" href="#openhands-condensers" aria-label="Permalink to &quot;OpenHands Condensers&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/All-Hands-AI/OpenHands" target="_blank" rel="noreferrer">https://github.com/All-Hands-AI/OpenHands</a></li><li><strong>License:</strong> MIT</li></ul><p>The most comprehensive compaction system in the coding agent ecosystem. OpenHands implements ~10 pluggable condenser strategies that can be chained into pipelines.</p><p><strong>Available condensers:</strong></p><ul><li><code>ObservationMaskingCondenser</code> — redact large outputs (command results, logs)</li><li><code>RecentEventsCondenser</code> — keep only the last N events</li><li><code>LLMSummarizingCondenser</code> — use an LLM to summarize older events</li><li><code>LLMAttentionCondenser</code> — LLM selects which events are most important</li><li><code>BrowserOutputCondenser</code> — specialized compaction for browser observations</li><li><code>AmortizedForgettingCondenser</code> — gradual decay of older events</li><li><code>LLMCondenser</code> — generic LLM-based compression</li><li>Pipeline combinators — chain condensers sequentially</li></ul><p><strong>Pipeline pattern example:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Raw events</span></span>
<span class="line"><span>  → ObservationMaskingCondenser (redact verbose tool outputs)</span></span>
<span class="line"><span>  → AmortizedForgettingCondenser (decay old events)</span></span>
<span class="line"><span>  → LLMSummarizingCondenser (summarize when budget exceeded)</span></span>
<span class="line"><span>  → Final context (fits within token budget)</span></span></code></pre></div><hr><h2 id="_5-code-rag-retrieval" tabindex="-1">5. Code RAG &amp; Retrieval <a class="header-anchor" href="#_5-code-rag-retrieval" aria-label="Permalink to &quot;5. Code RAG &amp; Retrieval&quot;">​</a></h2><p>Retrieval-Augmented Generation for code. These tools find and inject relevant code context on demand, rather than trying to keep everything in the window.</p><h3 id="llamaindex" tabindex="-1">LlamaIndex <a class="header-anchor" href="#llamaindex" aria-label="Permalink to &quot;LlamaIndex&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/run-llama/llama_index" target="_blank" rel="noreferrer">https://github.com/run-llama/llama_index</a></li><li><strong>License:</strong> MIT</li><li><strong>Stars:</strong> 38k+ (as of 2025)</li></ul><p>A data framework with first-class support for code. Its <code>CodeSplitter</code> does AST-aware chunking — splitting code at function/class boundaries rather than arbitrary line counts.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> llama_index</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">core</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">node_parser </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> CodeSplitter</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># AST-aware chunking: splits at function/class boundaries</span></span>
<span class="line"><span style="color:#CDD6F4;">splitter </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> CodeSplitter</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    language</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;python&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    chunk_lines</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">40</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">        # target chunk size</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    chunk_lines_overlap</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">5</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;"> # overlap between chunks</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    max_chars</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">1500</span><span style="color:#6C7086;font-style:italic;">         # hard limit</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Hierarchical indices: broad-to-narrow search</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Level 1: file-level summaries (cheap to search)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Level 2: class-level chunks (medium granularity)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Level 3: function-level chunks (precise retrieval)</span></span></code></pre></div><p><strong>Key features:</strong></p><ul><li><strong>Hierarchical indices</strong> — broad-to-narrow search (file → class → function)</li><li><strong>Hybrid retrieval</strong> — combine vector similarity with keyword search</li><li><strong>Metadata filtering</strong> — filter by language, file path, symbol type</li><li><strong>Streaming ingestion</strong> — process repos incrementally</li></ul><h3 id="voyage-ai-voyage-code-3" tabindex="-1">Voyage AI (voyage-code-3) <a class="header-anchor" href="#voyage-ai-voyage-code-3" aria-label="Permalink to &quot;Voyage AI (voyage-code-3)&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/voyage-ai/voyageai-python" target="_blank" rel="noreferrer">https://github.com/voyage-ai/voyageai-python</a></li><li><strong>Documentation:</strong> <a href="https://docs.voyageai.com" target="_blank" rel="noreferrer">https://docs.voyageai.com</a></li></ul><p>Code-specific embedding model that outperforms general-purpose embeddings by 15–30% on code retrieval benchmarks.</p><p><strong>Specifications:</strong></p><ul><li><strong>Context:</strong> 32,000 tokens (can embed entire files)</li><li><strong>Dimensions:</strong> 1024 (configurable: 256, 512, 1024)</li><li><strong>Training:</strong> fine-tuned on code with understanding of syntax, semantics, and documentation</li></ul><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> voyageai</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">client </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> voyageai</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">Client</span><span style="color:#9399B2;">()</span><span style="color:#6C7086;font-style:italic;">  # uses VOYAGE_API_KEY env var</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Embed code documents</span></span>
<span class="line"><span style="color:#CDD6F4;">doc_embeddings </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> client</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">embed</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    texts</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;def hello(): pass&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;class UserAuth: ...&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;voyage-code-3&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    input_type</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;document&quot;</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Embed a query (different input_type for asymmetric search)</span></span>
<span class="line"><span style="color:#CDD6F4;">query_embedding </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> client</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">embed</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    texts</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;authentication handler&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;voyage-code-3&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    input_type</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;query&quot;</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Reranking for precision (second pass after vector search)</span></span>
<span class="line"><span style="color:#CDD6F4;">reranked </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> client</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">rerank</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    query</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;authentication handler&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    documents</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">candidate_chunks</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;rerank-2&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    top_k</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">5</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Why code-specific embeddings matter:</strong> general embeddings treat code as text. Code embeddings understand that <code>authenticate_user</code> and <code>verify_credentials</code> are semantically related even though they share no words. They also understand that <code>def foo(x):</code> and <code>function foo(x)</code> are the same concept in different languages.</p><h3 id="chromadb" tabindex="-1">ChromaDB <a class="header-anchor" href="#chromadb" aria-label="Permalink to &quot;ChromaDB&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/chroma-core/chroma" target="_blank" rel="noreferrer">https://github.com/chroma-core/chroma</a></li><li><strong>License:</strong> Apache 2.0</li><li><strong>Stars:</strong> 16k+ (as of 2025)</li></ul><p>Embeddable vector database with a minimal 4-function API. Designed to be the &quot;SQLite of vector databases&quot; — zero-config, runs in-process.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> chromadb</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">client </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> chromadb</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">Client</span><span style="color:#9399B2;">()</span><span style="color:#6C7086;font-style:italic;">  # in-memory; use PersistentClient for disk</span></span>
<span class="line"><span style="color:#CDD6F4;">collection </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> client</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">create_collection</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;codebase&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Add code chunks with metadata</span></span>
<span class="line"><span style="color:#CDD6F4;">collection</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">add</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    documents</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;def login(user, pw): ...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;class AuthMiddleware: ...&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    ids</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;auth-login&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;auth-middleware&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    metadatas</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">[</span></span>
<span class="line"><span style="color:#9399B2;">        {</span><span style="color:#A6E3A1;">&quot;lang&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;python&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;file&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/auth.py&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;type&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;function&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">        {</span><span style="color:#A6E3A1;">&quot;lang&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;python&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;file&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/middleware.py&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;type&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;class&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">    ]</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Query with metadata filtering</span></span>
<span class="line"><span style="color:#CDD6F4;">results </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> collection</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">query</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    query_texts</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;how does authentication work?&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    n_results</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">5</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    where</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">&quot;lang&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;python&quot;</span><span style="color:#9399B2;">}</span><span style="color:#6C7086;font-style:italic;">  # filter by language</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Key pattern for agents:</strong> metadata filtering by file path, language, and symbol type. When an agent knows it&#39;s working on Python auth code, it can scope retrieval to <code>where={&quot;lang&quot;: &quot;python&quot;, &quot;file&quot;: {&quot;$contains&quot;: &quot;auth&quot;}}</code>.</p><h3 id="sweep" tabindex="-1">Sweep <a class="header-anchor" href="#sweep" aria-label="Permalink to &quot;Sweep&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/sweepai/sweep" target="_blank" rel="noreferrer">https://github.com/sweepai/sweep</a></li><li><strong>License:</strong> BUSL-1.1</li></ul><p>Multi-pass retrieval pipeline purpose-built for coding agents:</p><ol><li><strong>Lexical search</strong> — fast keyword matching (file names, identifiers)</li><li><strong>Embedding search</strong> — semantic similarity via vector embeddings</li><li><strong>LLM re-ranking</strong> — final pass where an LLM scores relevance</li></ol><p><strong>Additional features:</strong></p><ul><li>AST-aware chunking (tree-sitter based)</li><li>Incremental indexing on git changes (only re-index modified files)</li><li>Context-aware chunk expansion (include surrounding code for coherence)</li></ul><h3 id="greptile" tabindex="-1">Greptile <a class="header-anchor" href="#greptile" aria-label="Permalink to &quot;Greptile&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://greptile.com" target="_blank" rel="noreferrer">https://greptile.com</a></li><li><strong>License:</strong> Proprietary (API service), self-hosted option available</li><li><strong>Compliance:</strong> SOC 2 Type II</li></ul><p>Codebase understanding as a service. Indexes entire GitHub/GitLab repositories and provides a natural language API for querying code.</p><p><strong>Unique feature:</strong> learns team standards and patterns from PR review comments. Over time, it understands not just what the code does but how the team prefers to write code.</p><h3 id="cursor-codebase-indexing" tabindex="-1">Cursor Codebase Indexing <a class="header-anchor" href="#cursor-codebase-indexing" aria-label="Permalink to &quot;Cursor Codebase Indexing&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://docs.cursor.com/context/codebase-indexing" target="_blank" rel="noreferrer">https://docs.cursor.com/context/codebase-indexing</a></li></ul><p>The most successful consumer implementation of code RAG. Cursor indexes your entire codebase using embeddings and provides hybrid retrieval combining vector similarity with structural code understanding.</p><p><strong>Features:</strong></p><ul><li>Automatic re-indexing on file changes</li><li><code>.cursorignore</code> for scoping (exclude node_modules, build artifacts, etc.)</li><li>Hybrid search: embeddings + tree-sitter structural analysis</li><li>Incremental updates (only re-embed changed files)</li></ul><hr><h2 id="_6-persistence-memory-stores" tabindex="-1">6. Persistence &amp; Memory Stores <a class="header-anchor" href="#_6-persistence-memory-stores" aria-label="Permalink to &quot;6. Persistence &amp; Memory Stores&quot;">​</a></h2><p>Long-term memory that survives across sessions. These tools let agents remember user preferences, project context, and past decisions.</p><h3 id="sqlite-patterns" tabindex="-1">SQLite Patterns <a class="header-anchor" href="#sqlite-patterns" aria-label="Permalink to &quot;SQLite Patterns&quot;">​</a></h3><p>SQLite is the dominant choice for single-agent persistence. Zero-config, single-file, ACID-compliant, and available everywhere.</p><p><strong>How agents use SQLite:</strong></p><table tabindex="0"><thead><tr><th>Agent</th><th>SQLite Usage</th></tr></thead><tbody><tr><td>OpenCode</td><td><code>sessions</code> and <code>messages</code> tables for conversation history</td></tr><tr><td>Aider</td><td><code>diskcache</code> (SQLite-backed) for tree-sitter tag caching</td></tr><tr><td>LangGraph</td><td><code>SqliteSaver</code> for agent state checkpointing</td></tr><tr><td>Claude Code</td><td>Session persistence and conversation history</td></tr></tbody></table><p><strong>Common schema pattern:</strong></p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> sessions</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    created_at </span><span style="color:#CBA6F7;">TIMESTAMP</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> CURRENT_TIMESTAMP,</span></span>
<span class="line"><span style="color:#CDD6F4;">    metadata </span><span style="color:#CBA6F7;">JSON</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> messages</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    session_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> REFERENCES</span><span style="color:#CBA6F7;"> sessions</span><span style="color:#CDD6F4;">(id),</span></span>
<span class="line"><span style="color:#CBA6F7;">    role</span><span style="color:#CBA6F7;"> TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,       </span><span style="color:#6C7086;font-style:italic;">-- &#39;user&#39;, &#39;assistant&#39;, &#39;system&#39;, &#39;tool&#39;</span></span>
<span class="line"><span style="color:#CDD6F4;">    content </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    token_count </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    created_at </span><span style="color:#CBA6F7;">TIMESTAMP</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> CURRENT_TIMESTAMP</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> INDEX</span><span style="color:#89B4FA;font-style:italic;"> idx_messages_session</span><span style="color:#CBA6F7;"> ON</span><span style="color:#CDD6F4;"> messages(session_id, created_at);</span></span></code></pre></div><h3 id="mem0" tabindex="-1">Mem0 <a class="header-anchor" href="#mem0" aria-label="Permalink to &quot;Mem0&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/mem0ai/mem0" target="_blank" rel="noreferrer">https://github.com/mem0ai/mem0</a></li><li><strong>License:</strong> Apache 2.0</li><li><strong>Stars:</strong> 24k+ (as of 2025)</li></ul><p>Self-improving memory layer that automatically extracts facts from conversations, deduplicates them, and resolves conflicts.</p><p><strong>Multi-level memory:</strong></p><ul><li><strong>User level</strong> — preferences, expertise, communication style</li><li><strong>Session level</strong> — current task context, decisions made</li><li><strong>Agent level</strong> — learned patterns, tool preferences</li></ul><p><strong>Storage:</strong> hybrid vector + graph. Facts are stored as embeddings for semantic search AND as graph nodes for relational queries (&quot;what does this user&#39;s auth module depend on?&quot;).</p><p><strong>Claimed benchmarks:</strong> +26% accuracy vs OpenAI Memory, 91% faster retrieval, 90% fewer tokens consumed.</p><h3 id="zep" tabindex="-1">Zep <a class="header-anchor" href="#zep" aria-label="Permalink to &quot;Zep&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/getzep/zep" target="_blank" rel="noreferrer">https://github.com/getzep/zep</a></li><li><strong>License:</strong> Apache 2.0</li></ul><p>Long-term memory with automatic summarization and entity extraction.</p><p><strong>Key features:</strong></p><ul><li><strong>Auto-summarization</strong> — progressively summarizes older conversation turns</li><li><strong>Named entity extraction</strong> — identifies people, projects, technologies mentioned</li><li><strong>Temporal awareness</strong> — understands when facts were learned and can detect stale info</li><li><strong>Native LangChain integration</strong> — drop-in memory backend</li><li><strong>Hybrid search</strong> — vector similarity + metadata filtering</li></ul><h3 id="deerflow-built-in-harness-memory" tabindex="-1">DeerFlow (Built-In Harness Memory) <a class="header-anchor" href="#deerflow-built-in-harness-memory" aria-label="Permalink to &quot;DeerFlow (Built-In Harness Memory)&quot;">​</a></h3><ul><li><strong>URL:</strong> <a href="https://github.com/bytedance/deer-flow" target="_blank" rel="noreferrer">https://github.com/bytedance/deer-flow</a></li><li><strong>License:</strong> MIT</li></ul><p>DeerFlow implements memory directly in the harness rather than as a pluggable library. It combines several context management strategies into a single runtime:</p><p><strong>Within-session strategies:</strong></p><ul><li><strong>Sub-agent context isolation</strong> — each spawned sub-agent gets its own context window; only a compact <code>SubAgentResult</code> struct crosses back to the lead agent, not raw tool call history</li><li><strong>Progressive skill loading</strong> — Markdown skill files load on-demand (only the skills relevant to the current task), saving 2K–10K tokens per session compared to loading all skills upfront</li><li><strong>In-session summarization</strong> — when context usage crosses a threshold, completed sub-tasks are compressed from raw tool calls + results to a prose summary</li><li><strong>Filesystem offload</strong> — intermediate results (fetched pages, search results) are written to <code>/mnt/user-data/workspace/</code> rather than accumulated in context</li></ul><p><strong>Cross-session memory:</strong></p><ul><li>User profile, preferences, writing style, technical stack, and recurring workflows persist locally across sessions</li><li>Injected into the system prompt at session start: &quot;Based on past interactions, this user prefers...&quot;</li><li>Stored locally (user-controlled); not sent to external services by default</li></ul><p><strong>Comparison with Mem0/Zep:</strong></p><table tabindex="0"><thead><tr><th>Aspect</th><th>DeerFlow (built-in)</th><th>Mem0</th><th>Zep</th></tr></thead><tbody><tr><td>Fact extraction</td><td>Basic (profile/prefs)</td><td>Advanced (LLM-based, dedup)</td><td>Named entity + summarization</td></tr><tr><td>Multi-level memory</td><td>User + session</td><td>User + session + agent</td><td>User + session</td></tr><tr><td>Storage</td><td>Local files</td><td>Vector + graph</td><td>Vector + metadata</td></tr><tr><td>Integration</td><td>Built into harness</td><td>Python SDK, REST API</td><td>LangChain native</td></tr><tr><td>Setup</td><td>Zero (already included)</td><td>Moderate</td><td>Moderate</td></tr></tbody></table><p><strong>When to use:</strong> DeerFlow&#39;s built-in memory is the right choice when using DeerFlow as the harness. Use Mem0 or Zep when building a custom agent that needs advanced fact extraction, deduplication, or vector-based retrieval across large knowledge bases.</p><hr><h2 id="_7-retrieval-approach-comparison" tabindex="-1">7. Retrieval Approach Comparison <a class="header-anchor" href="#_7-retrieval-approach-comparison" aria-label="Permalink to &quot;7. Retrieval Approach Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Speed</th><th>Semantic Accuracy</th><th>Setup Cost</th><th>Best For</th></tr></thead><tbody><tr><td>Text grep</td><td>★★★★★</td><td>★★☆☆☆</td><td>None</td><td>Known identifiers, exact matches</td></tr><tr><td>tree-sitter structural</td><td>★★★★☆</td><td>★★★☆☆</td><td>Low</td><td>Symbol extraction, code navigation</td></tr><tr><td>Sparse retrieval (BM25)</td><td>★★★★☆</td><td>★★★☆☆</td><td>Low</td><td>Keyword-heavy queries</td></tr><tr><td>Dense retrieval (embeddings)</td><td>★★★☆☆</td><td>★★★★☆</td><td>Medium</td><td>Semantic code search</td></tr><tr><td>Code-specific embeddings</td><td>★★★☆☆</td><td>★★★★★</td><td>Medium</td><td>Cross-language code search</td></tr><tr><td>Hybrid (sparse + dense)</td><td>★★★☆☆</td><td>★★★★★</td><td>Medium</td><td>Production code search</td></tr><tr><td>LLM re-ranking</td><td>★★☆☆☆</td><td>★★★★★</td><td>High</td><td>Final-pass precision</td></tr><tr><td>Aider repo-map</td><td>★★★★☆</td><td>★★★★☆</td><td>Low</td><td>Repository overview, navigation</td></tr><tr><td>Multi-pass (Sweep-style)</td><td>★★☆☆☆</td><td>★★★★★</td><td>High</td><td>Complex code understanding</td></tr></tbody></table><p><strong>Key insight:</strong> most production agents use layered retrieval. Cheap methods (grep, tree-sitter) filter broadly, then expensive methods (embeddings, LLM re-ranking) refine. This balances speed and accuracy.</p><hr><h2 id="_8-memory-store-comparison" tabindex="-1">8. Memory Store Comparison <a class="header-anchor" href="#_8-memory-store-comparison" aria-label="Permalink to &quot;8. Memory Store Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Store</th><th>Auto-Extract</th><th>Summarization</th><th>Multi-Level</th><th>Search</th><th>Integration</th></tr></thead><tbody><tr><td>SQLite (raw)</td><td>✗</td><td>✗</td><td>Manual</td><td>SQL queries</td><td>Universal</td></tr><tr><td>Mem0</td><td>✓</td><td>✓</td><td>✓ (user/session/agent)</td><td>Vector + Graph</td><td>Python SDK</td></tr><tr><td>Zep</td><td>✓</td><td>✓</td><td>✓ (user/session)</td><td>Vector + Metadata</td><td>LangChain native</td></tr><tr><td>Letta</td><td>✓ (agent-driven)</td><td>✓ (agent-driven)</td><td>✓ (core/archival/recall)</td><td>Vector</td><td>REST API</td></tr><tr><td>ChromaDB</td><td>✗</td><td>✗</td><td>Manual</td><td>Vector + Metadata</td><td>Python/JS SDK</td></tr><tr><td>LangGraph Checkpoints</td><td>✗</td><td>✗</td><td>✗</td><td>By checkpoint ID</td><td>LangChain native</td></tr><tr><td>Redis (LangChain)</td><td>✗</td><td>✗</td><td>✗</td><td>Key-value + Vector</td><td>LangChain</td></tr></tbody></table><p><strong>Trade-offs:</strong></p><ul><li><strong>SQLite</strong> is the pragmatic default — add complexity only when you need it.</li><li><strong>Mem0</strong> is best when you want automatic fact extraction without building it yourself.</li><li><strong>Zep</strong> is best when LangChain integration and temporal awareness matter.</li><li><strong>Letta</strong> is best when the agent should manage its own memory (most autonomous).</li><li><strong>ChromaDB</strong> is best for pure retrieval without memory management overhead.</li></ul><hr><h2 id="_9-how-to-choose-tools" tabindex="-1">9. How to Choose Tools <a class="header-anchor" href="#_9-how-to-choose-tools" aria-label="Permalink to &quot;9. How to Choose Tools&quot;">​</a></h2><h3 id="decision-framework" tabindex="-1">Decision Framework <a class="header-anchor" href="#decision-framework" aria-label="Permalink to &quot;Decision Framework&quot;">​</a></h3><p><strong>Step 1: What&#39;s your model provider?</strong></p><ul><li>OpenAI only → tiktoken</li><li>Multiple providers → Hugging Face tokenizers</li><li>Browser/client-side → gpt-tokenizer or llama-tokenizer-js</li></ul><p><strong>Step 2: How big is the codebase?</strong></p><ul><li>Small (&lt; 50 files) → full file inclusion, no RAG needed</li><li>Medium (50–500 files) → tree-sitter repo-map (Aider-style)</li><li>Large (500+ files) → full RAG pipeline (embeddings + vector store)</li><li>Monorepo / multi-repo → Sourcegraph or Greptile</li></ul><p><strong>Step 3: What kind of memory do you need?</strong></p><ul><li>No persistence → in-memory buffers (LangChain ConversationBufferMemory)</li><li>Session persistence → SQLite</li><li>Cross-session learning → Mem0 or Zep</li><li>Agent-managed memory → Letta</li></ul><p><strong>Step 4: What&#39;s your budget?</strong></p><ul><li>Zero cost → tiktoken + tree-sitter + SQLite + ChromaDB (all open-source, local)</li><li>Low cost → add Voyage AI embeddings ($0.06/1M tokens)</li><li>Medium cost → add LLM-based summarization and re-ranking</li><li>Full budget → Greptile or Sourcegraph for managed infrastructure</li></ul><h3 id="common-tool-combinations" tabindex="-1">Common Tool Combinations <a class="header-anchor" href="#common-tool-combinations" aria-label="Permalink to &quot;Common Tool Combinations&quot;">​</a></h3><p><strong>Minimal (Aider-style):</strong> tiktoken + tree-sitter + SQLite → accurate counting, structural maps, session persistence</p><p><strong>Mid-range (Continue-style):</strong> tiktoken + tree-sitter + ChromaDB + code embeddings → adds semantic retrieval</p><p><strong>Full pipeline (Cursor-style):</strong> tokenizer + tree-sitter + custom embeddings + vector store + LLM re-ranking → maximum retrieval quality</p><p><strong>Autonomous agent (Letta-style):</strong> tokenizer + Letta memory system + vector store → agent manages its own context</p><h3 id="final-recommendations" tabindex="-1">Final Recommendations <a class="header-anchor" href="#final-recommendations" aria-label="Permalink to &quot;Final Recommendations&quot;">​</a></h3><ol><li><strong>Always start with accurate token counting.</strong> Everything else depends on it.</li><li><strong>tree-sitter is non-negotiable</strong> for any serious code agent. The structural understanding it provides is too valuable to skip.</li><li><strong>SQLite is the right default</strong> for persistence. Upgrade to Mem0/Zep only when you need automatic fact extraction or cross-session learning.</li><li><strong>Embeddings are worth it</strong> for repos over ~100 files. The retrieval quality improvement justifies the cost and complexity.</li><li><strong>Layer your retrieval.</strong> Cheap methods first (grep, tree-sitter), expensive methods second (embeddings, LLM re-ranking). Never start with the most expensive approach.</li></ol>`,188)])])}const u=n(o,[["render",l]]);export{g as __pageData,u as default};
